// === SCMA-KVK Parser (v5: title + date + correct excerpt-before-"читати більше") ===

const html = items[0].json.body || items[0].json.data || "";
if (!html || html.length < 50) {
  return [{ json: { error: "HTML не найден. Проверь HTTP Request node." } }];
}

// берём только первые 15 <article>…</article>
const postRegex = /<article[\s\S]*?<\/article>/gi;
const posts = (html.match(postRegex) || []).slice(0, 30);

const normText = s =>
  s.replace(/<[^>]+>/g, " ")     // убираем HTML
   .replace(/\s+/g, " ")         // сжимаем пробелы
   .replace(/&nbsp;/gi, " ")
   .trim();

const monthsUA = "(Січ|Лют|Бер|Кві|Тра|Чер|Лип|Сер|Вер|Жов|Лис|Гру)";
const monthRuEn = "(Янв|Фев|Мар|Апр|Мая|Июн|Июл|Авг|Сен|Окт|Ноя|Дек|Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)";
const dateRegexLoose = new RegExp(`\\b(${monthsUA}|${monthRuEn})\\.?\\s?\\d{1,2},?\\s?\\d{4}\\b`);

const results = [];

for (const post of posts) {
  // --- Title ---
  const mTitle = post.match(/<h2[^>]*>\s*<a[^>]*>(.*?)<\/a>\s*<\/h2>/i);
  const title = mTitle ? normText(mTitle[1]) : "";

  // --- Date (ищем разные варианты) ---
  let date = "";
  const mSpan = post.match(/<span[^>]*class=["']?published["']?[^>]*>(.*?)<\/span>/i);
  if (mSpan) date = normText(mSpan[1]);

  if (!date) {
    const mTime = post.match(/<time[^>]*>(.*?)<\/time>/i);
    if (mTime) date = normText(mTime[1]);
  }

  if (!date) {
    const mMeta = post.match(/<p[^>]*class=["']?post-meta["']?[^>]*>(.*?)<\/p>/i);
    if (mMeta) date = normText(mMeta[1]);
  }

  if (!date) {
    const afterH2 = post.split(/<\/h2>/i)[1] || "";
    const mLoose = afterH2.match(dateRegexLoose);
    if (mLoose) date = normText(mLoose[0]);
  }

  // --- Description (строго текст до "читати більше" / "читать дальше" / "read more") ---
  // 1) Вырезаем контентную часть после заголовка
  const afterTitleHtml = post.split(/<\/h2>/i)[1] || post;
  // 2) Обрезаем по ссылке "read more"
  const readMoreRe = /<a[^>]*>(?:читати\s+(?:більше|далі)|читать\s+дальше|read\s+more)<\/a>/i;
  const cutAtReadMore = readMoreRe.test(afterTitleHtml)
    ? afterTitleHtml.split(readMoreRe)[0]
    : afterTitleHtml;

  // 3) Пробуем найти явный контейнер с контентом
  let contentChunk = cutAtReadMore;
  const mContainer = cutAtReadMore.match(
    /<div[^>]*class=["'][^"']*(?:entry-content|post-content|post-excerpt|excerpt|the-excerpt)[^"']*["'][^>]*>([\s\S]*?)<\/div>/i
  );
  if (mContainer) contentChunk = mContainer[1];

  // 4) Берём первый осмысленный <p>, не являющийся метаданными
  let description = "";
  const pMatches = contentChunk.match(/<p[^>]*>[\s\S]*?<\/p>/gi) || [];
  for (const p of pMatches) {
    const txt = normText(p);
    if (!txt) continue;
    // отбрасываем явные мета-строки (дата, телефоны, "ЗА КОНСУЛЬТАЦІЄЮ ..." и т.п.)
    const looksLikeDate = dateRegexLoose.test(txt);
    const isMeta = /^(тел|phone|за консультацією|контакти|контакты)/i.test(txt);
    const containsReadMoreWord = /(читати|читать|read)\s+(більше|далі|дальше|more)/i.test(txt);
    if (!looksLikeDate && !isMeta && !containsReadMoreWord && txt.length > 20) {
      description = txt;
      break;
    }
  }

  // 5) Если подходящего <p> не нашли, берём «сырой» текст между датой и read more
  if (!description) {
    let raw = normText(contentChunk);
    // вырезаем саму дату, если она попала внутрь
    if (date && raw.startsWith(date)) raw = raw.slice(date.length).trim();
    // иногда в начале бывает служебный мусор — укоротим «заголовок/дату», если остались
    description = raw;
  }

  // 6) Безопасное усечение до 200 символов по слову
  const limit = 200;
  if (description.length > limit) {
    const cut = description.slice(0, limit);
    description = (cut.lastIndexOf(" ") > 0 ? cut.slice(0, cut.lastIndexOf(" ")) : cut) + "…";
  }

  if (title) results.push({ title, date, description });
}

if (results.length === 0) {
  return [{ json: { error: "Не удалось найти статьи/описания. Проверь HTML-разметку страницы." } }];
}

return results.map(r => ({ json: r }));

