const items = $input.all();

const formatted = items.map(item => {
  const title = item.json.title || "";
  const date = item.json.date || "";
  const description = item.json.description || "";
  return `• ${title} (${date}) — ${description}`;
}).join('\n\n');

return [{ json: { output: formatted } }];

// Получаем текущий элемент и сохраняем бинарные данные
const item = $input.first();

// Универсальный поиск размера файла (из разных мест JSON)
let rawSize =
  item.json.fileSize ||
  item.json.data?.fileSize ||
  item.json.metadata?.fileSize ||
  '0 B';

// Нормализуем строку
rawSize = String(rawSize).trim().replace(/\s+/g, ' ');

// Парсим и переводим в байты
const match = rawSize.match(/^([\d.,]+)\s*([KMGT]?B)$/i);
let bytes = 0;

if (match) {
  const number = parseFloat(match[1].replace(',', '.'));
  const unit = (match[2] || 'B').toUpperCase();
  const multipliers = {
    B: 1,
    KB: 1024,
    MB: 1024 ** 2,
    GB: 1024 ** 3,
    TB: 1024 ** 4
  };
  bytes = Math.round(number * (multipliers[unit] || 1));
}

// Возвращаем обновлённый объект с бинарными данными
return [
  {
    json: {
      fileSizeRaw: rawSize,
      fileSizeBytes: bytes,
      hasImage: bytes > 0
    },
    binary: item.binary // ⚡ сохраняем изображение для последующих узлов
  }
];
